Handlebars.registerHelper("formatPrice", (price) => {
  const num = Number(price);

  return !isNaN(num)
    ? num.toLocaleString("en-IE", {
        style: "currency",
        currency: "EUR",
      })
    : "€0.00";
});

Handlebars.registerHelper("formatKms", (kms) => {
  const num = Number(kms);

  if (isNaN(num)) return "";

  return num.toLocaleString("en-IE");
});

Handlebars.registerHelper("formatColour", (colour) => {
  return colour
    .split(" ")
    .map((w) => (w ? w[0].toUpperCase() + w.substring(1).toLowerCase() : ""))
    .join(" ");
});

